/**
 * ServiceRequestRegistry is a centralized registry for managing service requests.
 * It provides methods to register, retrieve, and manage service request objects.
 */

class ServiceRequestRegistry {
  private static instance: ServiceRequestRegistry;
  private serviceRequests: Map<string, ServiceRequest>;

  private constructor() {
    this.serviceRequests = new Map();
  }

  public static getInstance(): ServiceRequestRegistry {
    if (!ServiceRequestRegistry.instance) {
      ServiceRequestRegistry.instance = new ServiceRequestRegistry();
    }
    return ServiceRequestRegistry.instance;
  }

  public registerServiceRequest(serviceId: string, request: ServiceRequest): void {
    this.serviceRequests.set(serviceId, request);
  }

  public getServiceRequest(serviceId: string): ServiceRequest | undefined {
    return this.serviceRequests.get(serviceId);
  }

  public removeServiceRequest(serviceId: string): void {
    this.serviceRequests.delete(serviceId);
  }
}
